async def fetch_trades(
    client: httpx.AsyncClient,
    ticker: str,
    creds: Credentials | None,
    *,
    min_ts: int | None = None,
    max_ts: int | None = None,
) -> tuple[list[dict], str]:
    """Try /markets/trades first (public). If empty, try /historical/trades.

    min_ts/max_ts (Unix seconds) bound the query when known (market open/close
    from the universe parquet) — reduces pagination on high-volume tickers.
    """
    base_params: dict = {"ticker": ticker, "limit": 1000}
    if min_ts is not None:
        base_params["min_ts"] = min_ts
    if max_ts is not None:
        base_params["max_ts"] = max_ts

    live = await _paginate(client, "/markets/trades", dict(base_params), creds=None)
    if live:
        return live, "live"

    hist = await _paginate(client, "/historical/trades", dict(base_params), creds=None)
    if hist:
        return hist, "historical"

    if creds is not None:
        hist_auth = await _paginate(
            client, "/historical/trades", dict(base_params), creds=creds
        )
        if hist_auth:
            return hist_auth, "historical_auth"

    return [], "none"

